import{_ as e,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"31. Rotation To A General Practice Training Program","description":"","frontmatter":{"title":"31. Rotation To A General Practice Training Program","eba":"Doctors in Training 2022-2026","topics":["hours","rosters","employment","consultation"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/31-rotation-to-a-general-practice-training-program.md","filePath":"ebas/doctors-in-training/doctor-employment/31-rotation-to-a-general-practice-training-program.md"}'),n={name:"ebas/doctors-in-training/doctor-employment/31-rotation-to-a-general-practice-training-program.md"};function i(s,t,c,l,p,g){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="_31-rotation-to-a-general-practice-training-program" tabindex="-1">31. Rotation To A General Practice Training Program <a class="header-anchor" href="#_31-rotation-to-a-general-practice-training-program" aria-label="Permalink to &quot;31. Rotation To A General Practice Training Program&quot;">​</a></h1><p><strong>31.1</strong> The Program Teaching Practice must provide in writing the terms and conditions of Rotation one month prior to the Doctor commencing the term. Such terms and conditions must include details of:</p><p><strong>(a)</strong> rostered hours of work;</p><p><strong>(b)</strong> educational activities provided;</p><p><strong>(c)</strong> paid release time for training program educational activities; and</p><p><strong>(d)</strong> the name of the Doctor in the Practice who will be the designated supervisor. A supervisor must be available for consultation during all periods of duty.</p><p><strong>31.2</strong> The Program Teaching Practice will provide the Parent Hospital with details of any leave taken (including personal/carer’s leave and annual leave) during the general practice rotation.</p><p><strong>31.3</strong> A maximum of one week&#39;s annual leave may be taken in any 13 week Program Teaching Practice rotation. The Program Teaching Practice must pay this annual leave entitlement either to the Doctor, if leave is taken, or to the Parent Hospital for subsequent payment to the Doctor when leave is taken.</p><p><strong>31.4</strong> The individual Program Teaching Practice must pay the respective Doctor for time worked in the period of employment with the Program Teaching Practice.</p><p><strong>31.5</strong> The individual Program Teaching Practice shall be responsible for:</p><p><strong>(a)</strong> payment of personal/carer’s leave (to the extent of any credit advised by the Parent Hospital) taken whilst the Doctor is in a period of employment with the Program Teaching Practice; and</p><p><strong>(b)</strong> pro-rata annual leave payment to the Doctor, either paid for leave taken or pay an equivalent amount to the Parent Hospital;</p><p><strong>(c)</strong> workers compensation for the Doctor during the period of the employment with the Program Teaching Practice.</p><p><strong>31.6</strong> A Doctor rotated to a Program Teaching Practice situated more than 50 kilometres from the Parent Hospital must be provided with accommodation, including married accommodation if requested, during the period of Rotation free of charge. Married accommodation shall mean married quarters for married Doctors or Doctors in a domestic relationship accompanied by their family.</p><p><strong>31.7</strong> A Doctor rotated to a Program Teaching Practice situated more than 50 kilometres from their Parent Hospital shall be entitled to the Travelling Allowance set out in <a href="/eba/ebas/doctors-in-training/allowances/55-travelling-allowance-use-of-private-vehicle.html">clause 55</a> (Travelling Allowance – Use of Private Vehicle) for travel between the Parent Hospital and the Program Teaching Practice:</p><p><strong>(a)</strong> at the commencement and termination of Rotation; and</p><p><strong>(b)</strong> once every four weeks of the 13 week Rotation; and</p><p><strong>(c)</strong> for all work-related travel required by the practice.</p><p><strong>31.8</strong> Payment must only be made pursuant to subclause 31.7 if travel is undertaken by the Doctor.</p><p><strong>31.9</strong> For the purpose of this clause 31, the Parent Hospital will be the Hospital from which the Doctor is rotated (refer <a href="/eba/ebas/doctors-in-training/preliminary/3-definitions.html">clause 3</a> definitions). In the event that a Doctor commences the first ever term in Victoria on Rotation the Parent Hospital shall be that Hospital to which the Doctor was appointed.</p><p><strong>31.10</strong> The Parent Hospital must ensure continuity of employment conditions are met by maintaining such records as are required under this Agreement.</p><p><strong>31.11</strong> The Parent Hospital must ensure (subject to the appointment being filled) that Rotations to Program Teaching Practices occur and must not cancel Rotations, or recall Doctors during Rotation to meet its own service needs, without the agreement of the Program Teaching Practice.</p><p><strong>31.12</strong> Out of Hours Work</p><p><strong>(a)</strong> The Program Teaching Practice must pay the Doctor for work undertaken in the Program Teaching Practice out of hours or after the completion of 38 hours at the rate of:</p><p><strong>(i)</strong> 40% of all fees generated by the Doctor; or</p><p><strong>(ii)</strong> the applicable entitlement afforded to the Doctor in accordance with the Medical Practitioners Award 2010,</p><p>whichever is the greater.</p><p><strong>(b)</strong> Out of hours pursuant to subclause 31.12(a) above shall mean outside the hours of</p><p><strong>8.00</strong> a.m. to 6.00 p.m. Monday to Friday and 8.00 a.m. to 12.00 noon Saturday.</p><p><strong>(c)</strong> The application of this subclause 31.12 shall exclude the Doctor from any entitlement to the On-call (<a href="/eba/ebas/doctors-in-training/hours-of-work/38-on-call.html">clause 38</a>) or Recall (<a href="/eba/ebas/doctors-in-training/hours-of-work/39-recall-return-to-workplace.html">clause 39</a>) provisions of this Agreement.</p><p>Plain language terms: GP rotation, GP training.</p>',31)])])}const d=e(n,[["render",i]]);export{m as __pageData,d as default};
